package reseq_test

import (
	"net/netip"
	"testing"
	"time"

	"github.com/7mind/wanbond/internal/reseq"
)

type fixedClock struct{ t time.Time }

func (c *fixedClock) Now() time.Time                  { return c.t }
func (c *fixedClock) NewTimer(d time.Duration) reseq.Timer { return nopTimer{} }

type nopTimer struct{}

func (nopTimer) C() <-chan time.Time    { return nil }
func (nopTimer) Reset(d time.Duration)  {}
func (nopTimer) Stop() bool             { return true }

var src = netip.MustParseAddrPort("192.0.2.1:1")

func drainAll(r *reseq.Resequencer) []uint64 {
	var out []uint64
	for {
		it, ok := r.Pop()
		if !ok {
			return out
		}
		out = append(out, it.Seq)
	}
}

// Defect A: restart while next <= window+1 -> pendingLow predicate unsatisfiable -> permanent blackhole.
func TestSmallAnchorRestartBlackholes(t *testing.T) {
	r := reseq.New(64, time.Second, &fixedClock{time.Unix(0, 0)})
	// Old boot sent only 50 frames before restarting (well under one window).
	for s := uint64(0); s < 50; s++ {
		r.Observe(s, []byte{1}, src)
	}
	_ = drainAll(r)
	r.RebaselineToLow() // restart signal; anchor = 50, window = 64: no seq can be >64 below 50
	// New boot's entire stream:
	for s := uint64(1); s < 500; s++ {
		r.Observe(s, []byte{2}, src)
	}
	got := drainAll(r)
	if len(got) == 0 {
		t.Fatalf("BLACKHOLE CONFIRMED: 499 new-boot frames all dropped; DroppedSuspect=%d", r.Stats().DroppedSuspect)
	}
	t.Logf("delivered %d frames (no blackhole)", len(got))
}

// Defect B: plain Rebaseline (D32 hub failover) does not clear pendingLow -> stale gate survives.
func TestRebaselineDoesNotClearPendingLow(t *testing.T) {
	r := reseq.New(64, time.Second, &fixedClock{time.Unix(0, 0)})
	for s := uint64(0); s < 200; s++ {
		r.Observe(s, []byte{1}, src)
	}
	_ = drainAll(r)
	r.RebaselineToLow() // restart pending, anchor=200
	r.Rebaseline()      // D32 hub failover: documented "next Observe re-anchors"
	// Fail-back hub's stream continues HIGH (>= old anchor):
	for s := uint64(300); s < 400; s++ {
		r.Observe(s, []byte{2}, src)
	}
	got := drainAll(r)
	// Rebaseline's contract: first frame re-anchors, stream flows.
	if len(got) < 90 {
		t.Fatalf("Rebaseline contract broken by surviving pendingLow: delivered only %d of 100 frames; DroppedSuspect=%d", len(got), r.Stats().DroppedSuspect)
	}
}
EOF
